// OpenMP Kernel Functions translated from OpenCL
void bpnn_layerforward_omp(float *input_cuda,
                           float *output_hidden_cuda,
                           float *input_hidden_cuda,
                           float *hidden_partial_sum,
                           int in,
                           int hid) 
{
    int num_blocks = in / BLOCK_SIZE;

    #pragma omp parallel for
    for (int by = 0; by < num_blocks; by++) {
        float local_input_node[HEIGHT];
        float local_weight_matrix[HEIGHT * WIDTH];

        for (int ty = 0; ty < HEIGHT; ty++) {
            int index_in = HEIGHT * by + ty + 1;
            local_input_node[ty] = input_cuda[index_in];
        }

        for (int ty = 0; ty < HEIGHT; ty++) {
            for (int tx = 0; tx < WIDTH; tx++) {
                int index = (hid + 1) * HEIGHT * by + (hid + 1) * ty + tx + 1 + (hid + 1);
                local_weight_matrix[ty * WIDTH + tx] = input_hidden_cuda[index];
                local_weight_matrix[ty * WIDTH + tx] *= local_input_node[ty];
            }
        }

        for (int i = 1; i <= HEIGHT; i *= 2) {
            int power_two = i;
            for (int ty = 0; ty < HEIGHT; ty++) {
                if (ty % power_two == 0) {
                    int partner = ty + power_two/2;
                    if (partner < HEIGHT) {
                        for (int tx = 0; tx < WIDTH; tx++) {
                            local_weight_matrix[ty * WIDTH + tx] += local_weight_matrix[partner * WIDTH + tx];
                        }
                    }
                }
            }
        }

        for (int ty = 0; ty < HEIGHT; ty++) {
            for (int tx = 0; tx < WIDTH; tx++) {
                int index = (hid + 1) * HEIGHT * by + (hid + 1) * ty + tx + 1 + (hid + 1);
                input_hidden_cuda[index] = local_weight_matrix[ty * WIDTH + tx];
            }
        }

        for (int ty = 0; ty < HEIGHT; ty++) {
            hidden_partial_sum[by * hid + ty] = local_weight_matrix[ty];
        }
    }
}

void bpnn_adjust_weights_omp(float *delta,   
                             int hid,         
                             float *ly,      
                             int in,          
                             float *w,       
                             float *oldw)
{
    int num_blocks = in / BLOCK_SIZE;

    #pragma omp parallel for
    for (int by = 0; by < num_blocks; by++) {
        for (int ty = 0; ty < HEIGHT; ty++) {
            for (int tx = 0; tx < WIDTH; tx++) {
                int index = (hid + 1) * HEIGHT * by + (hid + 1) * ty + tx + 1 + (hid + 1);  
                int index_y = HEIGHT * by + ty + 1;
                int index_x = tx + 1;
                float dw = (ETA * delta[index_x] * ly[index_y]) + (MOMENTUM * oldw[index]);
                w[index] += dw;
                oldw[index] = dw;
            }
        }
    }

    if (num_blocks > 0) {
        for (int tx = 0; tx < WIDTH; tx++) {
            int index_x = tx + 1;
            float dw = (ETA * delta[index_x] * ly[1]) + (MOMENTUM * oldw[index_x]);
            w[index_x] += dw;
            oldw[index_x] = dw;
        }
    }
}

int bpnn_train_kernel(BPNN *net, float *eo, float *eh)
{
    int in, hid, out;
    float out_err, hid_err, sum;

    in = net->input_n;
    hid = net->hidden_n;
    out = net->output_n;

    int num_blocks = in / BLOCK_SIZE;
    float *input_weights_one_dim;
    float *input_weights_prev_one_dim;
    float *partial_sum;

    input_weights_one_dim = (float *) malloc((in + 1)* (hid + 1) * sizeof(float));
    input_weights_prev_one_dim = (float *) malloc((in + 1)* (hid + 1) * sizeof(float));
    partial_sum = (float *) malloc(num_blocks * WIDTH * sizeof(float));

    int m = 0;
    for (int k = 0; k <= in; k++) {
        for (int j = 0; j <= hid; j++) {
            input_weights_one_dim[m] = net->input_weights[k][j];
            input_weights_prev_one_dim[m] = net->input_prev_weights[k][j];
            m++;
        }
    }

    printf("Performing CPU computation\n");

    bpnn_layerforward_omp(net->input_units, net->hidden_units, input_weights_one_dim, partial_sum, in, hid);

    for (int j = 1; j <= hid; j++) {
        sum = 0.0;
        for (int k = 0; k < num_blocks; k++) {
            sum += partial_sum[k * hid + j-1];
        }
        sum += net->input_weights[0][j];
        net->hidden_units[j] = 1.0 / (1.0 + exp(-sum));
    }

    bpnn_layerforward(net->hidden_units, net->output_units, net->hidden_weights, hid, out);
    bpnn_output_error(net->output_delta, net->target, net->output_units, out, &out_err);
    bpnn_hidden_error(net->hidden_delta, hid, net->output_delta, out, net->hidden_weights, net->hidden_units, &hid_err);

    bpnn_adjust_weights(net->output_delta, out, net->hidden_units, hid, net->hidden_weights, net->hidden_prev_weights);

    bpnn_adjust_weights_omp(net->hidden_delta, hid, net->input_units, in, input_weights_one_dim, input_weights_prev_one_dim);

    m = 0;
    for (int k = 0; k <= in; k++) {
        for (int j = 0; j <= hid; j++) {
            net->input_weights[k][j] = input_weights_one_dim[m];
            net->input_prev_weights[k][j] = input_weights_prev_one_dim[m];
            m++;
        }
    }

    free(input_weights_one_dim);
    free(input_weights_prev_one_dim);
    free(partial_sum);

    *eo = out_err;
    *eh = hid_err;

    return 0;
}

int layer_size = 0;

void load(BPNN *net)
{
    float *units;
    int nr, i, k;
    nr = layer_size;
    units = net->input_units;
    k = 1;
    for (i = 0; i < nr; i++) {
        units[k] = (float) rand()/RAND_MAX;
        k++;
    }
}

void backprop_face()
{
    BPNN *net;
    float out_err, hid_err;
    net = bpnn_create(layer_size, 16, 1); 
    printf("Input layer size : %d\n", layer_size);
    load(net);
    printf("Starting training kernel\n");
    bpnn_train_kernel(net, &out_err, &hid_err);
    bpnn_free(net);
    printf("\nFinish the training for one iteration\n");
}

int setup(int argc, char **argv)
{
    layer_size = -1;
    int cur_arg;
    for (cur_arg = 1; cur_arg < argc; cur_arg++) {
        if (strcmp(argv[cur_arg], "-h") == 0) {
            fprintf(stderr, "usage: backprop <-n num of input elements>\n");
            exit(0);
        }
        else if (strcmp(argv[cur_arg], "-n") == 0) {
            if (cur_arg + 1 < argc) {
                layer_size = atoi(argv[cur_arg+1]);
                cur_arg++;
            }
        }
    }
    if (layer_size <= 0 || layer_size % 16 != 0){
        fprintf(stderr, "The number of input points must be divided by 16\n");
        exit(0);
    }
    int seed = 7;
    bpnn_initialize(seed);
    backprop_face();
    exit(0);
}

int main(int argc, char** argv)
{
    setup(argc, argv);
    return 0;
}
